class Solution:
    def minimumLength(self, s: str) -> int:
        left, right = 0, len(s) - 1
        while left < right:
            if s[left] == s[right]:
                while left <= right and s[left] == s[left + 1]:
                    left += 1
                while left <= right and s[right] == s[right - 1]:
                    right -= 1
                left += 1
                right -= 1
            else:
                break
        return right - left + 1
```
